const retailNewsXml = results.find(r => r.name === 'Google News Retail')?.text || '';
const mapaXml = results.find(r => r.name === 'MAPA Alimentación')?.text || '';
const facuaXml = results.find(r => r.name === 'FACUA Consumo')?.text || '';
