const shared = $('Fetch Shared Sources').first().json;
const items = $input.all();
const outputs = [];

function parseRSS(xml) {
  const out = [];
  const rx = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = rx.exec(xml || '')) !== null) {
    const b = m[1];
    const title = (b.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s) || [])[1] || '';
    const link = (b.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s) || [])[1] || '';
    const desc = (b.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s) || [])[1] || '';
    const pubDate = (b.match(/<pubDate[^>]*>(.*?)<\/pubDate>/s) || [])[1] || '';
    out.push({ title: title.trim(), link: link.trim(), desc: desc.trim(), pubDate: pubDate.trim() });
  }
  return out;
}

function strip(s='') {
  return String(s).replace(/<[^>]*>/g, ' ').replace(/&[a-z]+;/gi, ' ').replace(/\s+/g, ' ').trim();
}

function safeIsoDate(raw) {
  try { return raw ? new Date(raw).toISOString().split('T')[0] : new Date().toISOString().split('T')[0]; }
  catch { return new Date().toISOString().split('T')[0]; }
}

function normalizeKey(v) {
  return String(v || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
}

function buildKeywordSet(config) {
  const base = [
    'comercio local','pyme','autonomo','autónomo','hosteleria','hostelería',
    'subvencion','subvención','digitalizacion','digitalización','kit digital',
    'iva','energia','energía','alquiler','empleo','consumo','proveedores'
  ];
  const dynamic = [
    ...(config.keywords || []),
    ...(config.rss_filter_hints || []),
    config.business_type,
    config.city
  ].filter(Boolean);
  return [...new Set([...base, ...dynamic].map(normalizeKey).filter(Boolean))];
}

function scoreText(text, keywords) {
  const normalized = normalizeKey(text);
  let score = 0;
  for (const kw of keywords) {
    if (normalized.includes(kw)) score += kw.length > 8 ? 4 : 2;
  }
  return Math.min(score, 10);
}

function parseNews(config) {
  const keywords = buildKeywordSet(config);
  const newsItems = parseRSS(shared.newsXml || '');
  return newsItems.map(item => {
    const src = item.link.includes('elpais') ? 'El País' :
                item.link.includes('europapress') ? 'Europa Press' :
                item.link.includes('cincodias') ? 'Cinco Días' : 'Prensa';
    const relevance = scoreText(`${item.title} ${item.desc}`, keywords);
    return {
      id: 'news_' + Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
      title: strip(item.title),
      summary: strip(item.desc).slice(0, 320),
      source: src,
      url: item.link,
      date: safeIsoDate(item.pubDate),
      category: 'noticias',
      relevance,
      tags: keywords.filter(kw => normalizeKey(`${item.title} ${item.desc}`).includes(kw)).slice(0, 8)
    };
  }).filter(n => n.relevance >= 3).sort((a,b) => b.relevance - a.relevance).slice(0, 15);
}

function parseBoe(config) {
  const keywords = buildKeywordSet(config);
  const boeItems = parseRSS(shared.boeXml || '');
  const subsidies = [];
  const regulations = [];
  for (const item of boeItems) {
    const text = `${item.title} ${item.desc}`;
    const normalized = normalizeKey(text);
    if (!keywords.some(kw => normalized.includes(kw))) continue;
    const common = {
      id: Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
      title: strip(item.title),
      summary: strip(item.desc).slice(0, 300),
      url: item.link
    };
    if (/(ley|reglamento|obligacion|obligación|normativa|sancion|sanción)/i.test(text)) {
      regulations.push({
        id: `reg_${common.id}`,
        title: common.title,
        type: 'normativa',
        summary: common.summary,
        url: common.url,
        impact: /(obligacion|obligación|sancion|sanción)/i.test(text) ? 'high' : 'medium',
        action_required: 'Revisar requisitos, plazos y adaptación operativa'
      });
    } else {
      subsidies.push({
        id: `sub_${common.id}`,
        title: common.title,
        type: /formacion|formación/i.test(text) ? 'formación' : /subvencion|subvención/i.test(text) ? 'subvención' : 'ayuda',
        amount_range: '',
        deadline: '',
        target: 'Pymes y autónomos',
        url: common.url,
        status: 'abierta'
      });
    }
  }
  return { subsidies: subsidies.slice(0, 10), regulations: regulations.slice(0, 10) };
}

function processIneData(shared) {
  const signals = [];
  const fecha = new Date().toISOString();
  function parseIneSeries(data, label) {
    if (!Array.isArray(data)) return;
    for (const serie of data.slice(0, 15)) {
      const nombre = (serie.Nombre || '').replace(/<[^>]*>/g, '').trim();
      const datos = serie.Data || [];
      if (!nombre || datos.length === 0) continue;
      const ultimo = datos[0].Valor;
      const penultimo = datos.length > 1 ? datos[1].Valor : null;
      const variacion = (ultimo != null && penultimo != null && penultimo !== 0)
        ? ((ultimo - penultimo) / penultimo * 100).toFixed(2) : '0';
      signals.push({
        name: nombre.substring(0, 150), value: ultimo, previous_value: penultimo,
        variation_pct: parseFloat(variacion), unit: 'index', source: label,
        description: `${nombre} — Var: ${variacion}%`, captured_at: fecha
      });
    }
  }
  try { parseIneSeries(typeof shared.ineIpc === 'string' ? JSON.parse(shared.ineIpc) : shared.ineIpc, 'INE-IPC'); } catch {}
  try { parseIneSeries(typeof shared.ineRetailSales === 'string' ? JSON.parse(shared.ineRetailSales) : shared.ineRetailSales, 'INE-Ventas-Retail'); } catch {}
  return signals;
}

function processEnergy(shared) {
  const html = shared.energyHtml || '';
  const signals = [];
  const fecha = new Date().toISOString();
  const precioMatch = html.match(/(?:precio medio|media)[^0-9]{0,80}?(\d{1,4}[.,]\d{1,4})\s*(?:€\/(?:MWh|kWh)|cts)/i)
    || html.match(/(\d{1,3}[.,]\d{2,4})\s*€\/MWh/i);
  if (precioMatch) {
    signals.push({ name: 'electricidad_pvpc_media', value: parseFloat(precioMatch[1].replace(',', '.')), unit: 'EUR/MWh', source: 'ESIOS-REE', description: 'Precio medio PVPC electricidad hoy', captured_at: fecha });
  }
  return signals;
}

function parseRetailNews(config, xml) {
  const keywords = buildKeywordSet(config);
  const newsItems = parseRSS(xml || '');
  return newsItems.map(item => {
    const relevance = scoreText(`${item.title} ${item.desc}`, keywords);
    return {
      id: 'retail_' + Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
      title: strip(item.title),
      summary: strip(item.desc).slice(0, 320),
      source: 'Google News Retail',
      url: item.link,
      date: safeIsoDate(item.pubDate),
      category: 'retail',
      relevance,
      tags: keywords.filter(kw => normalizeKey(`${item.title} ${item.desc}`).includes(kw)).slice(0, 8)
    };
  }).filter(n => n.relevance >= 2).sort((a,b) => b.relevance - a.relevance).slice(0, 10);
}

function buildRetailPriceRadar(config, shared) {
  const keywords = buildKeywordSet(config);
  const extraKw = ['precio', 'coste', 'proveedor', 'mayorista', 'margen', 'inflacion', 'iva', 'tarifa', 'materia prima', 'logistica', 'transporte', 'alquiler'];
  const priceKeywords = [...new Set([...keywords, ...extraKw.map(normalizeKey)])];

  const signals = [];

  const mapaItems = parseRSS(shared.mapaXml || '');
  for (const item of mapaItems.slice(0, 10)) {
    const text = `${item.title} ${item.desc}`;
    const score = scoreText(text, priceKeywords);
    if (score >= 2) {
      signals.push({
        id: 'mapa_' + Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
        title: strip(item.title).slice(0, 200),
        summary: strip(item.desc).slice(0, 300),
        source: 'MAPA-Alimentación',
        url: item.link,
        type: 'supply_chain',
        relevance: score,
        impact: score >= 6 ? 'high' : 'medium',
        date: safeIsoDate(item.pubDate)
      });
    }
  }

  const facuaItems = parseRSS(shared.facuaXml || '');
  for (const item of facuaItems.slice(0, 10)) {
    const text = `${item.title} ${item.desc}`;
    const score = scoreText(text, priceKeywords);
    if (score >= 2) {
      signals.push({
        id: 'facua_' + Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
        title: strip(item.title).slice(0, 200),
        summary: strip(item.desc).slice(0, 300),
        source: 'FACUA-Consumo',
        url: item.link,
        type: 'consumer_alert',
        relevance: score,
        impact: /fraude|alerta|retirada|sancion/i.test(text) ? 'high' : 'medium',
        date: safeIsoDate(item.pubDate)
      });
    }
  }

  const priceItems = parseRSS(shared.priceNewsXml || '');
  for (const item of priceItems.slice(0, 10)) {
    const text = `${item.title} ${item.desc}`;
    const score = scoreText(text, priceKeywords);
    if (score >= 3) {
      signals.push({
        id: 'price_' + Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
        title: strip(item.title).slice(0, 200),
        summary: strip(item.desc).slice(0, 300),
        source: 'Prensa-Precios',
        url: item.link,
        type: 'price_intelligence',
        relevance: score,
        impact: score >= 6 ? 'high' : 'medium',
        date: safeIsoDate(item.pubDate)
      });
    }
  }

  return signals.sort((a, b) => b.relevance - a.relevance).slice(0, 15);
}

async function callModule(baseUrl, rawKey, path) {
  const authHeader = rawKey.startsWith('Bearer ') ? rawKey : `Bearer ${rawKey}`;
  try {
    const resp = await fetch(`${baseUrl}${path}`, {
      method: 'GET',
      headers: { 'Authorization': authHeader, 'Content-Type': 'application/json' },
      signal: AbortSignal.timeout(12000)
    });
    if (!resp.ok) return { ok: false, status: resp.status, data: null };
    return { ok: true, status: resp.status, data: await resp.json() };
  } catch (error) {
    return { ok: false, status: 0, data: null, error: error.message };
  }
}

