function buildCampaigns(config, context) {
  const bizName = config.business_name || 'Tu negocio';
  const bt = normalizeKey(config.business_type || 'comercio');
  const campaigns = [];
  const today = new Date();
  const iso = d => d.toISOString().split('T')[0];
  const month = today.getMonth();

  if (month === 0) {
    campaigns.push({
      title: 'Campaña Rebajas Enero', type: 'seasonal', channel: ['instagram','whatsapp','email'],
      target_audience: 'todos', suggested_date: iso(today),
      message_draft: `Rebajas de enero en ${bizName}. Ofertas especiales en toda la tienda. ¡No te lo pierdas!`,
      reason: 'Temporada de rebajas de enero — máxima demanda'
    });
  }
  if (month === 10) {
    campaigns.push({
      title: 'Campaña Black Friday', type: 'seasonal', channel: ['instagram','email','whatsapp'],
      target_audience: 'todos', suggested_date: iso(today),
      message_draft: `Black Friday en ${bizName}. Descuentos hasta el 70%. Aprovecha hoy.`,
      reason: 'Black Friday — máxima oportunidad de ventas'
    });
  }
  if (month === 11) {
    campaigns.push({
      title: 'Campaña Navidad', type: 'seasonal', channel: ['instagram','email','whatsapp'],
      target_audience: 'todos', suggested_date: iso(today),
      message_draft: `Regala desde ${bizName}. Nuestras mejores propuestas para Navidad. Envíos disponibles.`,
      reason: 'Navidad — temporada alta de consumo'
    });
  }

  if (['bar','cafeteria','cafetería','restaurante'].some(x => bt.includes(normalizeKey(x)))) {
    const tue = new Date(today.getTime() + ((9 - today.getDay()) % 7) * 86400000);
    campaigns.push({
      title: 'Promoción día valle', type: 'promotion', channel: ['whatsapp','instagram'],
      target_audience: 'clientes_recurrentes', suggested_date: iso(tue),
      message_draft: `Esta semana en ${bizName}: promo especial entre semana para aumentar tráfico en horas valle.`,
      reason: 'Optimización de ocupación entre semana'
    });
  }
  if ((context.reputation.reviews?.urgent || []).length > 0) {
    campaigns.push({
      title: 'Campaña recuperación reputacional', type: 'service_recovery', channel: ['email','whatsapp'],
      target_audience: 'clientes_insatisfechos', suggested_date: iso(new Date(today.getTime() + 86400000)),
      message_draft: `Gracias por seguir confiando en ${bizName}. Estamos mejorando nuestro servicio y queremos invitarte a volver.`,
      reason: 'Hay reseñas negativas urgentes pendientes'
    });
  }
  if ((context.market.price_signals || []).length > 0) {
    campaigns.push({
      title: 'Ajuste de oferta por costes', type: 'pricing', channel: ['interno'],
      target_audience: 'gerencia', suggested_date: iso(new Date(today.getTime() + 2 * 86400000)),
      message_draft: 'Revisar escandallos, márgenes y precios de productos clave por cambios de mercado.',
      reason: 'Se detectan señales de precio/proveedor'
    });
  }
  if ((context.calendar.free_slots || []).length > 0) {
    campaigns.push({
      title: 'Huecos libres para activar ventas', type: 'promotion', channel: ['whatsapp','instagram stories'],
      target_audience: 'clientes_recurrentes', suggested_date: iso(today),
      message_draft: `Tenemos disponibilidad/huecos libres hoy en ${bizName}. Reserva o ven a visitarnos.`,
      reason: 'Agenda con huecos libres detectados'
    });
  }
  if (campaigns.length === 0) {
    campaigns.push({
      title: 'Campaña semanal de visibilidad', type: 'content', channel: ['instagram','whatsapp'],
      target_audience: 'todos', suggested_date: iso(new Date(today.getTime() + 86400000)),
      message_draft: `Publica hoy una pieza sobre producto estrella, testimonio de cliente o promoción de la semana en ${bizName}.`,
      reason: 'Mantener presencia comercial continua'
    });
  }
  return campaigns.slice(0, 5);
}

function buildActionableTasks(config, context) {
  const tasks = [];
  const today = new Date().toISOString().split('T')[0];

  for (const email of (context.inbox.awaiting_reply || []).slice(0, 5)) {
    tasks.push({ type: 'email_reply', title: `Responder: ${email.subject || 'Email pendiente'}`, source: 'gmail', priority: email.priority || 'medium', due_date: today, entity_type: 'email', entity_id: email.thread_id || null, description: email.suggested_reply ? `Respuesta sugerida: ${email.suggested_reply}` : 'Pendiente de respuesta' });
  }
  for (const sr of (context.inbox.suggested_replies || []).slice(0, 3)) {
    tasks.push({ type: 'email_action', title: `Acción sugerida: ${sr.subject || 'Email'}`, source: 'gmail', priority: sr.priority || 'medium', due_date: today, description: sr.suggested_reply || '' });
  }

  for (const review of (context.reputation.reviews?.urgent || []).slice(0, 5)) {
    const suggested = (context.reputation.suggested_responses || []).find(sr => sr.author === review.author);
    tasks.push({ type: 'review_reply', title: `Responder reseña de ${review.author || 'Anónimo'}`, source: 'google_business', priority: 'high', due_date: today, entity_type: 'review', description: suggested ? `Respuesta sugerida: ${suggested.suggested_response}` : `Reseña ${review.rating} estrellas — requiere respuesta profesional` });
  }

  for (const reminder of (context.calendar.reminders || []).slice(0, 5)) {
    tasks.push({ type: 'calendar_action', title: reminder.title || 'Recordatorio de agenda', source: 'google_calendar', priority: 'medium', due_date: reminder.date || today, description: reminder.notes || '' });
  }
  for (const action of (context.calendar.action_items || []).slice(0, 3)) {
    tasks.push({ type: 'calendar_prep', title: action.title || `Preparar: ${action.event || ''}`, source: 'google_calendar', priority: 'medium', due_date: action.date || today, description: action.notes || '' });
  }

  for (const signal of (context.market.price_signals || []).slice(0, 3)) {
    tasks.push({ type: 'price_review', title: `Revisar precio: ${signal.title || 'Señal de mercado'}`, source: 'market', priority: signal.impact === 'high' ? 'high' : 'medium', due_date: today, description: signal.summary || '' });
  }
  for (const action of (context.market.action_items || []).slice(0, 3)) {
    tasks.push({ type: 'market_action', title: action.title || 'Acción de mercado', source: 'market', priority: action.priority || 'medium', due_date: today, description: action.description || '' });
  }

  for (const signal of (context.market.retail_price_radar || []).filter(s => s.impact === 'high').slice(0, 3)) {
    tasks.push({ type: 'price_alert', title: `Alerta precios: ${signal.title}`, source: signal.source, priority: 'high', due_date: today, description: signal.summary || '' });
  }

  for (const reg of (context.radar.regulations || []).slice(0, 3)) {
    tasks.push({ type: 'regulation_review', title: `Normativa: ${reg.title}`, source: 'boe', priority: reg.impact === 'high' ? 'high' : 'medium', due_date: today, description: reg.action_required || 'Revisar cambio normativo' });
  }

  for (const sub of (context.radar.subsidies || []).slice(0, 3)) {
    tasks.push({ type: 'subsidy_check', title: `Ayuda: ${sub.title}`, source: 'boe', priority: 'medium', due_date: today, description: `${sub.type} — ${sub.target || 'Pymes'}` });
  }

  return tasks.slice(0, 20);
}

function buildDailySummary(config, context) {
  const opportunities = (context.radar.subsidies?.length || 0) + (context.marketing.campaigns?.length || 0) + (context.calendar.free_slots?.length || 0);
  const risks = (context.radar.regulations?.length || 0) + (context.inbox.awaiting_reply?.length || 0) + (context.reputation.reviews?.urgent?.length || 0);
  const unread = context.inbox.unread_count || 0;
  const taskCount = context.tasks?.length || 0;
  const energySignals = (context.market.energy_signals || []).filter(s => s.value != null).length;
  const ipcChanges = (context.market.ine_signals || []).filter(s => Math.abs(s.variation_pct) > 1).length;
  const score = Math.max(0, Math.min(100,
    55
    + (context.radar.news?.length || 0) * 2
    + (context.radar.subsidies?.length || 0) * 4
    + (context.marketing.campaigns?.length || 0) * 3
    - (context.reputation.reviews?.urgent?.length || 0) * 8
    - (context.radar.regulations?.length || 0) * 5
    - (context.inbox.awaiting_reply?.length || 0) * 4
  ));

  let headline = `Hoy tienes ${context.radar.news.length} noticias relevantes`;
  if ((context.radar.subsidies || []).length > 0) headline += `, ${context.radar.subsidies.length} ayudas detectadas`;
  if (energySignals > 0 || ipcChanges > 0) headline += `, datos IPC/energía actualizados`;
  if (unread > 0) headline += ` y ${unread} email(s) sin leer`;
  if (taskCount > 0) headline += `. ${taskCount} tareas pendientes`;
  headline += '.';

  const actions = [];
  if ((context.inbox.awaiting_reply || []).length > 0) actions.push(`Responder ${context.inbox.awaiting_reply.length} conversación(es) pendientes`);
  if ((context.reputation.reviews?.urgent || []).length > 0) actions.push(`Atender ${context.reputation.reviews.urgent.length} reseña(s) urgente(s)`);
  if ((context.radar.regulations || []).length > 0) actions.push(`Revisar ${context.radar.regulations.length} cambio(s) normativo(s)`);
  if ((context.calendar.reminders || []).length > 0) actions.push(`Ejecutar ${context.calendar.reminders.length} recordatorio(s) de agenda`);
  if ((context.market.price_signals || []).length > 0) actions.push(`Revisar ${context.market.price_signals.length} señal(es) de precios/proveedores`);
  if ((context.market.retail_price_radar || []).length > 0) {
    const priceAlerts = context.market.retail_price_radar.filter(s => s.impact === 'high').length;
    if (priceAlerts > 0) actions.push(`Atender ${priceAlerts} alerta(s) de precios/proveedores`);
  }
  if ((context.market.energy_signals || []).length > 0) actions.push(`Analizar ${context.market.energy_signals.length} dato(s) de energía`);
  if ((context.market.ine_signals || []).length > 0) actions.push(`Considerar ${context.market.ine_signals.length} indicador(es) económico(s)`);
  if ((context.marketing.campaigns || []).length > 0) actions.push(`Lanzar ${context.marketing.campaigns.length} acción(es) de marketing sugeridas`);
  if ((context.radar.subsidies || []).length > 0) actions.push(`Evaluar ${context.radar.subsidies.length} ayuda(s)/subvención(es) disponibles`);

  return { headline, priority_actions: actions.slice(0, 8), opportunities_count: opportunities, risks_count: risks, score, tasks_count: taskCount };
}

for (const item of items) {
  const config = item.json;
  if (config._skip) { outputs.push({ json: { ...config, skipped: true } }); continue; }

  const baseUrl = config._auth_base_url || 'https://enlaze.vercel.app';
  const agentKey = config._auth_key || '';

  const radarNews = parseNews(config);
  const boe = parseBoe(config);
  const retailNews = parseRetailNews(config, shared.retailNewsXml || '');

  const modules = config.agent_modules_enabled || {};
  const gmailConnected = Boolean(config.gmail_connected || modules.gmail);
  const calendarConnected = Boolean(config.google_calendar_connected || modules.calendar);
  const businessConnected = Boolean(config.google_business_connected || config.google_place_id || modules.reputation);
  const marketConnected = Boolean(modules.market || true);
  const sheetsConnected = Boolean(config.google_sheets_connected || modules.sheets);

  const [gmailResp, calendarResp, reputationResp, marketResp, sheetsResp] = await Promise.all([
    gmailConnected ? callModule(baseUrl, agentKey, `/api/agent/gmail/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false }),
    calendarConnected ? callModule(baseUrl, agentKey, `/api/agent/calendar/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false }),
    businessConnected ? callModule(baseUrl, agentKey, `/api/agent/reputation/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false }),
    marketConnected ? callModule(baseUrl, agentKey, `/api/agent/market/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false }),
    sheetsConnected ? callModule(baseUrl, agentKey, `/api/agent/sheets/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false })
  ]);

  const inbox = gmailResp.ok && gmailResp.data ? { connected: true, ...gmailResp.data } : defaultInbox();
  const calendar = calendarResp.ok && calendarResp.data ? { connected: true, ...calendarResp.data } : defaultCalendar();
  const reputation = reputationResp.ok && reputationResp.data ? { connected: true, ...reputationResp.data } : defaultReputation();
  const market = marketResp.ok && marketResp.data ? { connected: true, ...marketResp.data } : defaultMarket();
  const sheets = sheetsResp.ok && sheetsResp.data ? { connected: true, ...sheetsResp.data } : defaultSheets();

  const ineSignals = processIneData(shared);
  const energySignals = processEnergy(shared);
  market.ine_signals = ineSignals;
  market.energy_signals = energySignals;
  market.cost_alerts = [
    ...energySignals.filter(s => s.value != null),
    ...ineSignals.filter(s => Math.abs(s.variation_pct) > 1)
  ].slice(0, 10);

  const retailPriceSignals = buildRetailPriceRadar(config, shared);
  market.retail_price_radar = retailPriceSignals;
  market.price_signals = [...(market.price_signals || []), ...retailPriceSignals.filter(s => s.type === 'price_intelligence').map(s => ({ title: s.title, summary: s.summary, source: s.source, impact: s.impact }))].slice(0, 15);
  market.supplier_alerts = [...(market.supplier_alerts || []), ...retailPriceSignals.filter(s => s.type === 'supply_chain').map(s => ({ title: s.title, summary: s.summary, source: s.source, impact: s.impact }))].slice(0, 10);

  const mergedRadarNews = [...radarNews, ...retailNews].sort((a,b) => b.relevance - a.relevance);
  const uniqueNews = Array.from(new Map(mergedRadarNews.map(n => [normalizeKey(n.title), n])).values()).slice(0, 20);

  const radar = {
    news: uniqueNews,
    regulations: boe.regulations,
    subsidies: boe.subsidies,
    competitor_signals: market.competitor_signals || [],
    local_events: market.market_signals || []
  };

  const campaigns = buildCampaigns(config, { inbox, calendar, reputation, market, radar });

  const tasks = buildActionableTasks(config, { inbox, calendar, reputation, market, radar });

  const automation = {
    gmail_connected: inbox.connected,
    calendar_connected: calendar.connected,
    google_business_connected: reputation.connected,
    google_sheets_connected: sheets.connected,
    module_status: {
      gmail: gmailResp.ok ? 'active' : gmailConnected ? 'error' : 'not_connected',
      calendar: calendarResp.ok ? 'active' : calendarConnected ? 'error' : 'not_connected',
      reputation: reputationResp.ok ? 'active' : businessConnected ? 'error' : 'not_connected',
      sheets: sheetsResp.ok ? 'active' : sheetsConnected ? 'error' : 'not_connected',
      market: marketResp.ok ? 'active' : 'fallback'
    },
    pending_tasks: tasks.filter(t => t.priority === 'high').slice(0, 5),
    total_tasks: tasks.length,
    backend_dependencies: {
      base_url: baseUrl,
      endpoints_required: [
        { path: '/api/agent/users', status: 'used_by_workflow', description: 'Lista usuarios activos del sector' },
        { path: '/api/agent/config', status: 'used_by_workflow', description: 'Configuración por usuario' },
        { path: '/api/agent/gmail/summary', status: gmailResp.ok ? 'active' : gmailConnected ? 'error' : 'not_configured', description: 'Resumen Gmail — requiere OAuth' },
        { path: '/api/agent/calendar/summary', status: calendarResp.ok ? 'active' : calendarConnected ? 'error' : 'not_configured', description: 'Resumen Calendar — requiere OAuth' },
        { path: '/api/agent/reputation/summary', status: reputationResp.ok ? 'active' : businessConnected ? 'error' : 'not_configured', description: 'Resumen Google Business — requiere place_id' },
        { path: '/api/agent/market/summary', status: marketResp.ok ? 'active' : 'fallback_to_public_sources', description: 'Señales de mercado' },
        { path: '/api/agent/sheets/summary', status: sheetsResp.ok ? 'active' : sheetsConnected ? 'error' : 'not_configured', description: 'Google Sheets — requiere OAuth' },
        { path: '/api/agent/ingest', status: 'used_by_workflow', description: 'Endpoint de ingesta de payload diario' }
      ],
      fully_autonomous_sources: ['INE IPC', 'INE Ventas Retail', 'ESIOS Energía', 'BOE Ayudas', 'RSS Prensa', 'MAPA Alimentación', 'FACUA Consumo', 'Google News Retail', 'Google News Precios'],
      note: 'Las fuentes autónomas funcionan sin backend. Gmail/Calendar/Sheets/Reputation requieren endpoints backend con OAuth configurado.'
    }
  };

  const payload = {
    user_id: config.user_id,
    business_id: config.business_id || config.user_id,
    business_name: config.business_name,
    business_type: config.business_type,
    city: config.city,
    sector: config.sector || 'comercio_local',
    agent: 'comercio_local',
    version: '6.1',
    timestamp: new Date().toISOString(),
    daily_summary: buildDailySummary(config, { inbox, calendar, reputation, market, radar, marketing: { campaigns }, tasks }),
    radar,
    inbox,
    calendar,
    reputation,
    market,
    sheets,
    marketing: { campaigns, upcoming_dates: calendar.next_events || [] },
    automation,
    tasks,
    connections: { gmail_connected: inbox.connected, google_calendar_connected: calendar.connected, google_business_connected: reputation.connected, google_sheets_connected: sheets.connected }
  };

  delete payload._auth_key;
  delete payload._auth_base_url;

  outputs.push({ json: payload });
}

return outputs;

return $input.all().map(item => {
  const r = item.json || {};
  return {
    json: {
      success: r.success === true || r.ok === true,
      timestamp: r.timestamp || new Date().toISOString(),
      user_id: r.user_id || null,
      results: r.results || {}
    }
  };
});
